import{c as p,Q as e,j as i,m as t}from"./chunks/framework.CpfXsn6-.js";const x=JSON.parse('{"title":"基本介绍","description":"","frontmatter":{"title":"基本介绍"},"headers":[],"relativePath":"developer/overview.md","filePath":"developer/overview.md","lastUpdated":1779163937000}'),n={name:"developer/overview.md"};function o(a,l,s,r,u,c){return e(),i("div",null,[...l[0]||(l[0]=[t(`<p>Trojan-Go-Next的核心部分有</p><ul><li><p>tunnel 各个协议具体实现</p></li><li><p>proxy 代理核心</p></li><li><p>config 配置注册和解析模块</p></li><li><p>redirector 主动检测欺骗模块</p></li><li><p>statistics 用户认证和统计模块</p></li></ul><p>可以在对应文件夹中找到相关源代码。</p><h2 id="tunnel-tunnel隧道" tabindex="-1">tunnel.Tunnel隧道 <a class="header-anchor" href="#tunnel-tunnel隧道" aria-label="Permalink to &quot;tunnel.Tunnel隧道&quot;">​</a></h2><p>Trojan-Go-Next将所有协议（包括路由功能等）抽象为隧道(tunnel.Tunnel接口)，每个隧道可开启服务端（tunnel.Server接口）和客户端（tunnel.Client）。每个服务端可以从其底层隧道中，剥离并接受流（tunnel.Conn）和包（tunnel.PacketConn)。客户端可以向底层隧道，创建流和包。</p><p>每个隧道并不关心其下方的隧道是什么，但是每个隧道清楚知道这个它上方的其他隧道的相关信息。</p><p>所有隧道需要下层提供流或包传输支持，或两者都要求提供。所有隧道必须向上层隧道提供流传输支持，但不一定提供包传输。</p><p>隧道可能只有服务端，也可能只有客户端，也可能两者皆有。两者皆有的隧道，可被用于作为Trojan-Go-Next客户端和服务端间的传输隧道。</p><p>注意，请区分Trojan-Go-Next的服务端/客户端，和隧道的服务端/客户端的区别。下面是一个方便理解的图例。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>  入站                              GFW                                  出站</span></span>
<span class="line"><span>--------&gt;隧道A服务端-&gt;隧道B客户端 ----------------&gt; 隧道B服务端-&gt;隧道C客户端-----------&gt;</span></span>
<span class="line"><span>           (Trojan-Go-Next客户端)                          (Trojan-Go-Next服务端)</span></span></code></pre></div><p>最底层的隧道为传输层，即不从其他隧道获取或者创建流和包的隧道，充当上图中隧道A或者C的角色。</p><ul><li><p>transport，可插拔传输层</p></li><li><p>socks，socks5代理，仅隧道服务端</p></li><li><p>tproxy，透明代理，仅隧道服务端</p></li><li><p>dokodemo，反向代理，仅隧道服务端</p></li><li><p>freedom，自由出站，仅隧道客户端</p></li></ul><p>这几个隧道直接从TCP/UDP Socket创建流和包，不接受为其底层添加的任何隧道。</p><p>其他隧道，只要下层能满足上层对包和流传输的需求，则原则上可以任何方式，任何数量进行组合和堆叠。这些隧道在上图中充当隧道B的角色，他们有</p><ul><li><p>trojan</p></li><li><p>websocket</p></li><li><p>mux</p></li><li><p>simplesocks</p></li><li><p>tls</p></li><li><p>router，路由功能，仅隧道客户端</p></li></ul><p>他们都不关心其下层隧道实现。但可以根据到来的流和包，将其分发给上层隧道。</p><p>例如，在这张图中，是一个典型的Trojan-Go-Next客户端和服务端，各个隧道自下往上堆叠的顺序是：</p><ul><li><p>隧道A: transport-&gt;socks</p></li><li><p>隧道B: transport-&gt;tls-&gt;trojan</p></li><li><p>隧道C: freedom</p></li></ul><p>实际上的隧道堆叠的情况会比这个更复杂一些。通常的入站的隧道是一棵多叉树的形式，而非一条链。具体解释参考下文。</p><h2 id="proxy-proxy代理核心" tabindex="-1">proxy.Proxy代理核心 <a class="header-anchor" href="#proxy-proxy代理核心" aria-label="Permalink to &quot;proxy.Proxy代理核心&quot;">​</a></h2><p>代理核心的作用，是监听上述隧道进行组合堆叠并形成的协议栈，将所有的入站协议栈（多个隧道Server的终端节点，见下）中抽取的流和包，以及对应元信息，转送给出站协议栈（一个隧道Client）。</p><p>注意，这里的入站协议栈可以有多个，如客户端可以同时从Socks5和HTTP协议栈中抽取流和包，服务端可以同时从Websocket承载的Trojan协议，和TLS承载的Trojan协议中抽取流和包等。但是出站协议栈只能有一个，如只使用TLS承载的Trojan协议出站。</p><p>为了描述入站协议栈（隧道服务端）的组合和堆叠方式，使用一棵多叉树对所有协议栈进行描述。你可以在proxy文件夹中各组件，看到构建树的过程。</p><p>而出站协议栈则比较简单，使用一个简单列表即可描述。</p><p>所以实际上，对于一个典型的开启了Websocket和Mux的客户端/服务端，上图的隧道堆叠模型为：</p><p>客户端</p><ul><li><p>入站（树）</p><ul><li>transport (根) <ul><li>adapter 能够识别HTTP和Socks流量并分发给上层协议 <ul><li>http （终端节点）</li><li>socks（终端节点）</li></ul></li></ul></li></ul></li><li><p>出站(链)</p><ul><li>transport (根)</li><li>tls</li><li>websocket</li><li>trojan</li><li>mux</li><li>simplesocks</li></ul></li></ul><p>服务端</p><ul><li><p>入站（树）</p><ul><li>transport (根) <ul><li>tls 能够识别HTTP和非HTTP流量并分发 <ul><li>websocket <ul><li>trojan（终端节点） <ul><li>mux <ul><li>simplesocks （终端节点）</li></ul></li></ul></li></ul></li><li>trojan 能够识别mux和普通trojan流量并分发（终端节点） <ul><li>mux <ul><li>simplesocks （终端节点）</li></ul></li></ul></li></ul></li></ul></li></ul></li><li><p>出站（链）</p><ul><li>freedom</li></ul></li></ul><p>注意，代理核心只从隧道构成的树的终端节点抽取流和包，并转送到唯一的出站上。多个终端节点的设计的目的，是使Trojan-Go-Next同时兼容Websocket和Trojan协议入站连接，开启/未开启Mux的入站连接，以及HTTP/Socks5自动识别的功能。每个拥有多个儿子的树上节点，具有精确识别和分发流和包给不同的儿子节点的能力。这符合我们假定每个协议了解其上层承载协议的假设。</p>`,30)])])}const T=p(n,[["render",o]]);export{x as __pageData,T as default};
